SELECT id, job_no, name, gender, age, phone, email, id_card, position_name, clinic_name, department_name, role_name, address, creator, enabled, created_at, updated_at, deleted FROM sys_staff WHERE deleted = 0
AND (job_no LIKE CONCAT('%', #{keyword}, '%') OR name LIKE CONCAT('%', #{keyword}, '%') OR phone LIKE CONCAT('%', #{keyword}, '%') OR department_name LIKE CONCAT('%', #{keyword}, '%') OR role_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE sys_staff
SET deleted = 1, updated_at = NOW()
WHERE id = #{id}
